#include <stdio.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        long long even=0, odd=0;
        for(int i=0;i<n;++i){
            int x; scanf("%d",&x);
            if(i%2==0) even+=x; else odd+=x;
        }
        printf("%lld\n", even-odd);
    }
    return 0;
}

