import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        even = 0
        odd = 0
        for i in range(n):
            x = int(next(it))
            if i % 2 == 0:
                even += x
            else:
                odd += x
        out.append(str(even - odd))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

